arguments.file_text:
@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" />
        <input type="text" placeholder="Assignee" @bind="assignee" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@saving">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <p class="form-error">@error</p>
        }
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            error = "Title and assignee are required.";
            return;
        }

        saving = true;
        error = null;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
            IsVisible = false;
            ResetForm();
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        error = null;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="board-heading">Kanban Board</h2>

@if (loading)
{
    <p class="board-loading">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="todoCounts"
                   InProgressCount="inProgressCounts"
                   DoneCount="doneCounts"
                   OverdueCount="overdueCounts" />

    <div class="search-bar">
        <input type="text" placeholder="Search tasks by title…"
               @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="kanban-board">
        <KanbanColumn ColumnName="To Do"
                      Tasks="filteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="filteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="task => MoveTask(task, \"To Do\")"
                      OnMoveRight="task => MoveTask(task, \"Done\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="Done"
                      Tasks="filteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="CreateTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    // Counts computed from unfiltered list
    private int todoCounts => allTasks.Count(t => t.Status == "To Do");
    private int inProgressCounts => allTasks.Count(t => t.Status == "In Progress");
    private int doneCounts => allTasks.Count(t => t.Status == "Done");
    private int overdueCounts => allTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");

    // Filtered lists for display
    private List<TaskItem> filteredTodo => Filter("To Do");
    private List<TaskItem> filteredInProgress => Filter("In Progress");
    private List<TaskItem> filteredDone => Filter("Done");

    private List<TaskItem> Filter(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchText) ||
                         t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(TaskItem draft)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

