/* ── Board layout ── */
.board-heading {
    margin: 1rem 0 0.5rem;
}

.board-loading,
.board-error {
    padding: 2rem;
    text-align: center;
}

.board-error {
    color: #b91c1c;
}

/* ── Stats bar ── */
.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f1f5f9;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.75rem;
    color: #64748b;
}

.stat-overdue .stat-value {
    color: #b91c1c;
}

/* ── Search ── */
.search-bar {
    margin-bottom: 1rem;
}

.search-bar input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #cbd5e1;
    border-radius: 6px;
    font-size: 0.875rem;
}

/* ── Kanban grid ── */
.kanban-board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1rem;
    align-items: start;
}

.kanban-column {
    background: #f8fafc;
    border-radius: 8px;
    padding: 0.75rem;
    min-height: 200px;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #e2e8f0;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
}

.column-count {
    background: #e2e8f0;
    border-radius: 999px;
    padding: 0.125rem 0.5rem;
    font-size: 0.75rem;
    font-weight: 600;
}

/* ── Task card ── */
.task-card {
    background: #fff;
    border: 1px solid #e2e8f0;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

.task-title {
    margin: 0 0 0.25rem;
    font-size: 0.875rem;
}

.task-assignee {
    margin: 0 0 0.375rem;
    font-size: 0.75rem;
    color: #64748b;
}

.priority-badge {
    display: inline-block;
    padding: 0.125rem 0.5rem;
    border-radius: 999px;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    margin-right: 0.5rem;
}

.priority-high {
    background: #fee2e2;
    color: #b91c1c;
}

.priority-medium {
    background: #fef9c3;
    color: #a16207;
}

.priority-low {
    background: #dcfce7;
    color: #15803d;
}

.task-due {
    font-size: 0.75rem;
    color: #64748b;
}

.task-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    font-size: 0.7rem;
    padding: 0.25rem 0.5rem;
    border: 1px solid #cbd5e1;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.btn-move:hover {
    background: #f1f5f9;
}

/* ── Add task ── */
.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    border: 2px dashed #cbd5e1;
    border-radius: 6px;
    background: transparent;
    color: #64748b;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-add-task:hover {
    border-color: #94a3b8;
    color: #334155;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    background: #fff;
    border: 1px solid #e2e8f0;
    border-radius: 6px;
    padding: 0.75rem;
}

.add-task-form input,
.add-task-form select {
    padding: 0.375rem 0.5rem;
    border: 1px solid #cbd5e1;
    border-radius: 4px;
    font-size: 0.8rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-save {
    padding: 0.375rem 0.75rem;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-cancel {
    padding: 0.375rem 0.75rem;
    background: #e2e8f0;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
}

.form-error {
    color: #b91c1c;
